head.b:skin:
:root {
  --bg: #f3f6fb;
  --surface: #ffffff;
  --text: #1c2634;
  --muted: #6b778c;
  --nav-dark: #263647;
  --top-dark: #1e2a37;
  --hero-dark: #1b2740;
  --hero-accent: #2f3d56;
  --primary: #2f6fed;
  --primary-hover: #1f56c4;
  --danger: #d83a52;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: 'Cairo', Arial, sans-serif;
  background: var(--bg);
  color: var(--text);
  line-height: 1.6;
}

a {
  text-decoration: none;
  color: inherit;
}

.container {
  width: min(1160px, 92%);
  margin: 0 auto;
}

.top-strip {
  background: var(--top-dark);
  color: #cfdae7;
  font-size: 0.88rem;
}

.top-strip-inner {
  min-height: 42px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
}

.top-contact {
  display: flex;
  align-items: center;
  gap: 18px;
}

.top-contact span,
.top-social a {
  display: inline-flex;
  align-items: center;
  gap: 6px;
}

.top-social {
  display: inline-flex;
  gap: 14px;
}

.site-header {
  background: var(--nav-dark);
  color: #ffffff;
  border-bottom: 1px solid rgba(255, 255, 255, 0.08);
}

.nav-bar {
  min-height: 84px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 24px;
}

.logo-wrap {
  min-width: 180px;
}

#header {
  width: 100%;
}

#header .widget,
#header .widget-content {
  text-align: left;
}

#header img {
  max-width: 210px;
  width: auto;
  height: auto;
}

#header h1,
#header h2,
#header .title {
  margin: 0;
  color: #ffffff;
  font-size: 1.3rem;
  font-weight: 800;
}

.primary-nav {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: flex-end;
  gap: 10px;
}

.primary-nav a {
  color: #ffffff;
  font-size: 0.9rem;
  font-weight: 700;
  letter-spacing: 0.02em;
  text-transform: uppercase;
  padding: 10px 12px;
  border-radius: 8px;
  transition: background-color 0.2s ease;
}

.primary-nav a:hover {
  background: rgba(255, 255, 255, 0.12);
}

.primary-nav .login-link {
  background: var(--primary);
  text-transform: none;
}

.primary-nav .login-link:hover {
  background: var(--primary-hover);
}

.hero {
  position: relative;
  background: linear-gradient(150deg, var(--hero-dark) 0%, #202e4a 55%, var(--hero-accent) 100%);
  color: #ffffff;
  padding: 80px 0 96px;
  overflow: hidden;
}

.hero::before {
  content: '';
  position: absolute;
  inset: 0;
  background: radial-gradient(circle at 20% 30%, rgba(255, 255, 255, 0.08) 0, transparent 42%),
    radial-gradient(circle at 80% 70%, rgba(255, 255, 255, 0.05) 0, transparent 36%);
  pointer-events: none;
}

.hero-inner {
  position: relative;
  z-index: 1;
  text-align: center;
}

.hero h1 {
  margin: 0;
  font-size: clamp(1.8rem, 3.4vw, 2.9rem);
  font-weight: 800;
  letter-spacing: 0.02em;
}

.hero p {
  margin: 14px auto 0;
  max-width: 860px;
  color: rgba(255, 255, 255, 0.9);
}

.search-wrap {
  margin: 38px auto 0;
  max-width: 860px;
}

.search-card {
  background: var(--surface);
  border-radius: 14px;
  box-shadow: 0 18px 45px rgba(10, 23, 44, 0.3);
  padding: 26px;
}

.search-form {
  display: flex;
  gap: 12px;
}

.search-form input[name='q'] {
  flex: 1;
  min-height: 58px;
  border: 1px solid #d4dce8;
  border-radius: 10px;
  padding: 0 16px;
  font-size: 1rem;
  font-family: inherit;
  outline: none;
  background: #ffffff;
  transition: border-color 0.2s ease, box-shadow 0.2s ease;
}

.search-form input[name='q']:focus {
  border-color: var(--primary);
  box-shadow: 0 0 0 3px rgba(47, 111, 237, 0.16);
}

.search-form button {
  min-height: 58px;
  border: 0;
  border-radius: 10px;
  padding: 0 24px;
  font-family: inherit;
  font-size: 1rem;
  font-weight: 700;
  color: #ffffff;
  background: var(--primary);
  cursor: pointer;
  transition: background-color 0.2s ease;
}

.search-form button:hover {
  background: var(--primary-hover);
}

.content-section {
  padding: 48px 0 78px;
}

.empty-state,
.result-card {
  background: var(--surface);
  border: 1px solid #e2e8f2;
  border-radius: 14px;
  box-shadow: 0 8px 24px rgba(18, 32, 54, 0.08);
  padding: 24px;
}

.result-card + .result-card {
  margin-top: 18px;
}

.result-title {
  margin: 0 0 14px;
  text-align: center;
  color: #22344d;
  font-size: 1.4rem;
  font-weight: 800;
  word-break: break-word;
}

.result-body {
  text-align: center;
}

.result-body img {
  max-width: 100%;
  height: auto;
  border-radius: 10px;
  border: 1px solid #d7dfeb;
}

.not-found {
  margin: 0;
  text-align: center;
  color: var(--danger);
  font-size: 1.05rem;
  font-weight: 700;
}

.hint {
  margin: 0;
  text-align: center;
  color: var(--muted);
}

.site-footer {
  background: #111a2b;
  color: #ced8e6;
  padding: 42px 0;
}

.footer-inner {
  display: grid;
  grid-template-columns: 1.3fr 1fr 1fr;
  gap: 26px;
}

.footer-brand {
  font-size: 1.02rem;
  font-weight: 700;
}

.footer-meta {
  color: #aebace;
  font-size: 0.94rem;
}

.footer-title {
  margin: 0 0 10px;
  font-size: 1.02rem;
  color: #ffffff;
}

.footer-links,
.footer-contact {
  display: flex;
  flex-direction: column;
  gap: 8px;
  font-size: 0.94rem;
}

.footer-links a:hover,
.footer-contact a:hover,
.social-links a:hover {
  color: #ffffff;
}

.social-links {
  display: inline-flex;
  gap: 12px;
  margin-top: 12px;
}

@media (max-width: 980px) {
  .nav-bar {
    flex-direction: column;
    align-items: flex-start;
    padding: 16px 0;
  }

  .primary-nav {
    justify-content: flex-start;
  }

  .footer-inner {
    grid-template-columns: 1fr 1fr;
  }
}

@media (max-width: 768px) {
  .top-strip-inner,
  .top-contact {
    flex-direction: column;
    align-items: flex-start;
    padding: 8px 0;
  }

  .search-form {
    flex-direction: column;
  }

  .footer-inner {
    grid-template-columns: 1fr;
  }
}
